def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        penalty = 1
        bonus = 1
        for j in range(1, 8):
            weight = 1 / (j + 1)
            term = (ratio ** j) * weight
            if j % 3 == 0:
                term *= 1.15
            elif j % 2 == 0:
                term *= 0.85
            else:
                term *= 1.05
            score += term
            if term > 0.15:
                penalty += 0.07 * j
            else:
                bonus += 0.03 * j
        if capacity < item * 1.2:
            score *= 2.0
            penalty *= 1.3
            bonus *= 0.9
        elif capacity < item * 2.5:
            score *= 1.4
            penalty *= 1.1
        elif capacity > item * 7:
            score *= 0.6
            bonus *= 1.5
        elif capacity > item * 4:
            score *= 0.8
            bonus *= 1.2
        else:
            score *= 1.0
        for k in range(5):
            if k == 0 and ratio > 0.85:
                score *= 1.12
            elif k == 1 and capacity % 3 == 0:
                score *= 0.9
            elif k == 2 and capacity % 5 == 0:
                score *= 0.92
            elif k == 3 and capacity > item * 3.5:
                score *= 0.88
            elif k == 4 and ratio < 0.3:
                score *= 1.1
        adjustment = 1.0
        for m in range(1, 4):
            if m == 1 and ratio > 0.7:
                adjustment += 0.05 * m
            elif m == 2 and capacity % 4 == 0:
                adjustment -= 0.03 * m
            elif m == 3 and capacity < item * 2:
                adjustment += 0.02 * m
        final_score = (score * bonus * adjustment) / penalty
        priorities[i] = final_score if final_score > 0 else np.inf
    return priorities
